import { Requisition } from "@/types";

// Define strict policies
export const APPROVAL_POLICIES = {
    // General rule: Requests under $500 auto-approve (simulated by assigning to 'AUTO')
    // or arguably just go straight to PO. For now, let's require approval for everything > $0.

    LIMITS: {
        MANAGER: 1000,    // Managers can approve up to $1,000
        DIRECTOR: 5000,   // Directors can approve up to $5,000
        VP: 10000,        // VPs can approve up to $10,000
        CXO: Infinity     // C-Level approves everything else
    },

    // Mock approvers for development (In a real app, these would come from a Users DB with 'Role' and 'Department')
    APPROVERS: {
        IT: {
            MANAGER: { uid: 'auth-it-manager', name: 'IT Manager', email: 'it.manager@example.com' },
            DIRECTOR: { uid: 'auth-it-director', name: 'IT Director', email: 'it.director@example.com' },
        },
        Marketing: {
            MANAGER: { uid: 'auth-mkt-manager', name: 'Marketing Manager', email: 'mkt.manager@example.com' },
        },
        Operations: {
            MANAGER: { uid: 'auth-ops-manager', name: 'Ops Manager', email: 'ops.manager@example.com' },
        },
        General: {
            FINANCE: { uid: 'auth-finance', name: 'Finance Controller', email: 'finance@example.com' } // Fallback
        }
    }
};

export interface ApproverInfo {
    uid: string;
    name: string;
    email: string;
    role: string;
}

// Logic to determine who should approve the request
export const getApproverForRequest = (department: string, amount: number): ApproverInfo => {
    // 1. Normalize department
    const dept = (APPROVAL_POLICIES.APPROVERS as any)[department] || APPROVAL_POLICIES.APPROVERS.General;

    // 2. Check thresholds
    // Simple logic: If < 1000 -> Manager. If > 1000 -> Finance (Fallback for easier testing)
    // In a real complex app, we'd traverse up the hierarchy.

    if (amount <= APPROVAL_POLICIES.LIMITS.MANAGER && dept.MANAGER) {
        return { ...dept.MANAGER, role: 'MANAGER' };
    }

    if (amount <= APPROVAL_POLICIES.LIMITS.DIRECTOR && dept.DIRECTOR) {
        return { ...dept.DIRECTOR, role: 'DIRECTOR' };
    }

    // Default High Value -> Finance Controller
    return { ...APPROVAL_POLICIES.APPROVERS.General.FINANCE, role: 'FINANCE' };
};
